package com.km.tag.unit;import javax.servlet.http.HttpServletRequest;public class UnitModel {    public static void calc(HttpServletRequest request) {        double n = Double.parseDouble(request.getParameter("num"));        String unit = request.getParameter("unit");        String cc = "d";        double result =  n * 0.6213;        String convertUnit = "mi/h";        if (unit.equals("cm")) {            result = n * 0.3937;            convertUnit = "inch";            cc = "a";        } else if (unit.equals("㎡")) {            result = n * 0.3025;            convertUnit = "평";            cc = "b";        } else if (unit.equals("°C")) {            result = n * 1.8 + 32;            convertUnit = "°F";            cc = "c";        }        String result2 = String.format("%.2f", result);        UnitVO unitvo = new UnitVO(n,unit, cc, result2, convertUnit);        request.setAttribute("unit", unitvo);    }}